s=p?'\u062a\u0646\u0637\u0628\u0642 \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0647\u0630\u0647 \u0639\u0644\u0649 \u0643\u0627\u0641\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0634\u062e\u0635\u064a\u0629\u060c \u0648\u0627\u0644\u062a\u064a \u062a\u0642\u0648\u0645 \u0628\u062a\u0642\u062f\u064a\u0645\u0647\u0627 \u0644\u0646\u0627 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0627\u0644\u0645\u0648\u0642\u0639 \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a. \u062a\u0645 \u0648\u0636\u0639 \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0647\u0630\u0647 \u0645\u0646 \u0623\u062c\u0644 \u062a\u0639\u0632\u064a\u0632 \u062b\u0642\u062a\u0643 \u062d\u064a\u0627\u0644 \u062e\u0635\u0648\u0635\u064a\u0629 \u0648\u0633\u0644\u0627\u0645\u0629 \u062a\u0641\u0627\u0635\u064a\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a\u0643 \u0627\u0644\u0634\u062e\u0635\u064a\u0629. \u0646\u0642\u0648\u0645 \u0628\u0627\u0644\u062a\u0639\u0627\u0645\u0644 \u0645\u0639 \u0643\u0627\u0641\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0648\u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u062a\u0639\u0644\u0642\u0629 \u0628\u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0628\u062a\u0648\u0627\u0641\u0642 \u062a\u0627\u0645 \u0645\u0639 \u0643\u0627\u0641\u0629 \u062a\u0634\u0631\u064a\u0639\u0627\u062a \u062d\u0645\u0627\u064a\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0630\u0627\u062a \u0627\u0644\u0639\u0644\u0627\u0642\u0629.\n\n\u0645\u0627\u0630\u0627 \u0646\u0641\u0639\u0644 \u0628\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062a\u064a \u062a\u0642\u062f\u0645\u0647\u0627 \u0625\u0644\u064a\u0646\u0627\n\u0644\u062f\u0649 \u0642\u064a\u0627\u0645\u0643 \u0628\u0625\u062f\u062e\u0627\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645\u060c \u0641\u0623\u0646\u062a \u062a\u0648\u0627\u0641\u0642 \u0628\u0623\u0646 \u0646\u0642\u0648\u0645 \u0646\u062d\u0646 \u0628\u0627\u0644\u0627\u062d\u062a\u0641\u0627\u0638 \u0628\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0648\u0630\u0644\u0643 \u0639\u0646 \u0637\u0631\u064a\u0642\u0646\u0627 \u0623\u0648 \u0639\u0646 \u0637\u0631\u064a\u0642 \u062e\u062f\u0645\u0627\u062a \u0634\u0631\u0643\u0629 \u062a\u0643\u0648\u0646 \u0637\u0631\u0641\u0627 \u062b\u0627\u0644\u062b\u0627 \u064a\u0642\u0648\u0645 \u0628\u0645\u0639\u0627\u0644\u062c\u0629 \u0647\u0630\u0647 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0628\u0627\u0644\u0646\u064a\u0627\u0628\u0629 \u0639\u0646\u0627. \u064a\u062c\u0648\u0632 \u0644\u0646\u0627 \u0623\u0646 \u0646\u0633\u062a\u062e\u062f\u0645 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0648\u0630\u0644\u0643 \u062d\u0633\u0628 \u0628\u0646\u0648\u062f \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0647\u0630\u0647 \u0645\u0646 \u0623\u062c\u0644 \u0627\u0644\u0623\u063a\u0631\u0627\u0636 \u0627\u0644\u062a\u0627\u0644\u064a\u0629:\n- \u0625\u062c\u0631\u0627\u0621 \u0623\u0628\u062d\u0627\u062b \u0627\u0644\u0633\u0648\u0642\u060c \u0628\u0645\u0627 \u0641\u064a \u0630\u0644\u0643 \u0627\u0644\u062a\u062d\u0644\u064a\u0644 \u0627\u0644\u0625\u062d\u0635\u0627\u0626\u064a \u0627\u0644\u0645\u062a\u0639\u0644\u0642 \u0628\u0633\u0644\u0648\u0643 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645\u060c \u0648\u0627\u0644\u062a\u064a \u064a\u062c\u0648\u0632 \u0644\u0646\u0627 \u0639\u0631\u0636\u0647\u0627 \u0639\u0644\u0649 \u0623\u0637\u0631\u0627\u0641 \u062b\u0627\u0644\u062b\u0629 \u0639\u0644\u0649 \u0646\u062d\u0648 \u063a\u064a\u0631 \u0634\u062e\u0635\u064a\u060c \u0648\u0628\u0634\u0643\u0644 \u0643\u0644\u064a.\n- \u062a\u0645\u0643\u064a\u0646\u0646\u0627 \u0645\u0646 \u0627\u0644\u0625\u064a\u0641\u0627\u0621 \u0628\u0643\u0627\u0641\u0629 \u0627\u0644\u0645\u062a\u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0645\u0641\u0631\u0648\u0636\u0629 \u0639\u0644\u064a\u0646\u0627 \u0642\u0627\u0646\u0648\u0646\u064a\u0627.\n- \u0625\u0631\u0633\u0627\u0644 \u0645\u062e\u0627\u0637\u0628\u0627\u062a \u062f\u0648\u0631\u064a\u0629 \u0625\u0644\u064a\u0643 (\u0648\u0627\u0644\u062a\u064a \u062a\u062a\u0636\u0645\u0646 \u0631\u0633\u0627\u0644\u0629 \u0628\u0631\u064a\u062f \u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a)\u060c \u0628\u062e\u0635\u0648\u0635 \u0627\u0644\u0645\u0648\u0627\u0635\u0641\u0627\u062a\u060c \u0648\u0627\u0644\u0645\u0646\u062a\u062c\u0627\u062a\u060c \u0648\u0627\u0644\u062e\u062f\u0645\u0627\u062a\u060c \u0648\u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a\u060c \u0648\u0627\u0644\u0639\u0631\u0648\u0636 \u0627\u0644\u062e\u0627\u0635\u0629.\n\n\u064a\u062c\u0648\u0632 \u0644\u0646\u0627 \u0623\u0646 \u0646\u0642\u0648\u0645 \u0628\u0627\u0644\u0625\u0641\u0635\u0627\u062d \u0639\u0646 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0625\u0644\u0649 \u0637\u0631\u0641 \u062b\u0627\u0644\u062b:\n- \u0645\u0646 \u0623\u062c\u0644 \u0623\u0646 \u064a\u0642\u0648\u0645 \u0627\u0644\u0637\u0631\u0641 \u0627\u0644\u062b\u0627\u0644\u062b \u0628\u0625\u0631\u0633\u0627\u0644 \u0645\u062e\u0627\u0637\u0628\u0627\u062a \u062f\u0648\u0631\u064a\u0629 \u0644\u0643 \u0628\u062e\u0635\u0648\u0635 \u0627\u0644\u0645\u0648\u0627\u0635\u0641\u0627\u062a\u060c \u0648\u0627\u0644\u0645\u0646\u062a\u062c\u0627\u062a\u060c \u0648\u0627\u0644\u062e\u062f\u0645\u0627\u062a\u060c \u0648\u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a\u060c \u0648\u0627\u0644\u0639\u0631\u0648\u0636 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0627\u0644\u0646\u064a\u0627\u0628\u0629 \u0639\u0646\u0627.\n- \u0641\u064a \u062d\u0627\u0644 \u0642\u0645\u0646\u0627 \u0628\u0628\u064a\u0639 \u0623\u0648 \u0634\u0631\u0627\u0621 \u0623\u0639\u0645\u0627\u0644 \u0623\u0648 \u0645\u0648\u062c\u0648\u062f\u0627\u062a\u060c \u0648\u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u062d\u0627\u0644\u0629 \u064a\u062c\u0648\u0632 \u0644\u0646\u0627 \u0623\u0646 \u0646\u0641\u0635\u062d \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0644\u0644\u0634\u0627\u0631\u064a \u0623\u0648 \u0627\u0644\u0628\u0627\u0626\u0639 \u0627\u0644\u0645\u062d\u062a\u0645\u0644 \u0644\u0645\u062b\u0644 \u0647\u0630\u0647 \u0627\u0644\u0623\u0639\u0645\u0627\u0644 \u0623\u0648 \u0627\u0644\u0645\u0645\u062a\u0644\u0643\u0627\u062a.\n- \u0641\u064a \u062d\u0627\u0644 \u062a\u0645\u0644\u0643 \u0637\u0631\u0641 \u062b\u0627\u0644\u062b \u0643\u0627\u0641\u0629 \u0645\u0648\u062c\u0648\u062f\u0627\u062a\u0646\u0627 \u0623\u0648 \u0645\u0639\u0638\u0645\u0647\u0627\u060c \u0641\u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u062d\u0627\u0644\u0629 \u062a\u0624\u0648\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0648\u0627\u0644\u062a\u064a \u0642\u0645\u062a \u0628\u062a\u0642\u062f\u064a\u0645\u0647\u0627 \u0644\u0646\u0627 \u0625\u0644\u0649 \u0627\u0644\u0637\u0631\u0641 \u0627\u0644\u062b\u0627\u0644\u062b \u0643\u062c\u0632\u0621 \u0645\u0646 \u0627\u0644\u0645\u0648\u062c\u0648\u062f\u0627\u062a \u0627\u0644\u0645\u0646\u0642\u0648\u0644\u0629 \u0644\u0647.\n- \u0641\u064a \u062d\u0627\u0644 \u062a\u0648\u062c\u0628 \u0639\u0644\u064a\u0646\u0627 \u0627\u0644\u0625\u0641\u0635\u0627\u062d \u0639\u0646 \u0623\u0648 \u0645\u0634\u0627\u0631\u0643\u0629 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0645\u0646 \u0623\u062c\u0644: \n  \u0623) \u0627\u0644\u0627\u0646\u0635\u064a\u0627\u0639 \u0644\u0644\u0627\u0644\u062a\u0632\u0627\u0645\u0627\u062a \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a\u0629.\n  \u0628) \u062a\u0637\u0628\u064a\u0642 \u0623\u0648 \u062a\u0646\u0641\u064a\u0630 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645 \u0648\u0623\u0648 \u0623\u064a \u0627\u062a\u0641\u0627\u0642\u064a\u0627\u062a \u0623\u062e\u0631\u0649.\n  \u062c) \u062d\u0645\u0627\u064a\u0629 \u062d\u0642\u0648\u0642\u0646\u0627\u060c \u0648\u0645\u0644\u0643\u064a\u062a\u0646\u0627\u060c \u0648\u0633\u0644\u0627\u0645\u062a\u0646\u0627\u060c \u0648\u0632\u0628\u0627\u0626\u0646\u0646\u0627\u060c \u0623\u0648 \u0645\u0633\u062a\u062e\u062f\u0645\u0648\u0646 \u0622\u062e\u0631\u0648\u0646.\n\n\u0642\u062f \u0646\u0642\u0648\u0645 \u0628\u0627\u0644\u0625\u0641\u0635\u0627\u062d \u0639\u0646 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0644\u0623\u064a \u0645\u0646 \u0627\u0644\u0634\u0631\u0643\u0627\u062a \u0627\u0644\u0645\u0646\u062a\u0645\u064a\u0629 \u0644\u0646\u0627\u060c \u0648\u0627\u0644\u062a\u064a \u0642\u062f \u062a\u062a\u0636\u0645\u0646 \u0634\u0631\u0643\u0627\u062a\u0646\u0627 \u0627\u0644\u0641\u0631\u0639\u064a\u0629 \u0648\u0634\u0631\u0643\u0627\u062a\u0646\u0627 \u0627\u0644\u0642\u0627\u0628\u0636\u0629\u060c \u0648\u0634\u0631\u0643\u0627\u062a\u0647\u0627 \u0627\u0644\u0641\u0631\u0639\u064a\u0629\u060c \u062d\u064a\u062b\u0645\u0627 \u0643\u0627\u0646 \u0645\u0648\u0642\u0639 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0643\u0627\u062a \u0641\u064a \u0627\u0644\u0639\u0627\u0644\u0645 \u0648\u0644\u0623\u064a \u0633\u0628\u0628 \u0643\u0627\u0646.\n\n\u0627\u0644\u062a\u062d\u062f\u064a\u062b\u0627\u062a\n\u062a\u0633\u062a\u0637\u064a\u0639 \u0623\u0646 \u062a\u0639\u0644\u0645\u0646\u0627 \u0628\u0623\u064a \u062a\u062d\u062f\u064a\u062b\u0627\u062a\u060c \u0648\u062a\u0639\u062f\u064a\u0644\u0627\u062a\u060c \u0648\u062a\u0635\u062d\u064a\u062d\u0627\u062a\u060c \u062a\u0642\u0648\u0645 \u0628\u0647\u0627 \u0639\u0644\u0649 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062a\u064a \u0642\u0645\u0646\u0627 \u0628\u062c\u0645\u0639\u0647\u0627 \u0645\u0633\u0628\u0642\u0627 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0648\u0635\u0644\u0629 \u0646\u0645\u0648\u0630\u062c \u0627\u0644\u062a\u063a\u0630\u064a\u0629 \u0627\u0644\u0631\u0627\u062c\u0639\u0629 \u0641\u064a \u0642\u0633\u0645 \u0627\u062a\u0635\u0644 \u0628\u0646\u0627 \u0627\u0644\u0645\u0648\u062c\u0648\u062f \u0639\u0644\u0649 \u0627\u0644\u0645\u0648\u0642\u0639. \u0642\u062f \u0646\u0642\u0648\u0645 \u0628\u062a\u063a\u064a\u064a\u0631 \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0645\u0646 \u0648\u0642\u062a \u0625\u0644\u0649 \u0622\u062e\u0631 \u0648\u0644\u0647\u0630\u0627 \u064a\u062a\u0639\u064a\u0646 \u0639\u0644\u064a\u0643 \u0645\u0631\u0627\u062c\u0639\u062a\u0647\u0627 \u062f\u0648\u0631\u064a\u0627. \u0648\u064a\u0643\u0648\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u0645\u0648\u0642\u0639 \u0633\u0643\u0627\u064a \u0646\u064a\u0648\u0632 \u0639\u0631\u0628\u064a\u0629 \u062f\u0644\u0627\u0644\u0629 \u0639\u0644\u0649 \u0642\u0628\u0648\u0644 \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0627\u0644\u0645\u0637\u0628\u0642\u0629 \u0641\u064a \u0630\u0644\u0643 \u0627\u0644\u0648\u0642\u062a. \u0646\u062d\u062a\u0641\u0638 \u0628\u062d\u0642\u0646\u0627 \u0628\u062a\u063a\u064a\u064a\u0631 \u0623\u0648 \u062a\u0639\u062f\u064a\u0644 \u0623\u0648 \u062a\u062d\u062f\u064a\u062b \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0647\u0630\u0647 \u0641\u064a \u0623\u064a \u0648\u0642\u062a \u0645\u0646 \u0627\u0644\u0623\u0648\u0642\u0627\u062a.\n\n\u062c\u0645\u0639 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a\n\u0639\u0646\u062f \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0648\u0642\u0639 \u0642\u062f \u062a\u0635\u0627\u062f\u0641 \u0645\u0646\u0627\u0637\u0642 \u0645\u062b\u0644 \u0627\u0644\u0645\u0646\u062a\u062f\u064a\u0627\u062a \u0623\u0648 \u062e\u062f\u0645\u0627\u062a \u0627\u0644\u0641\u064a\u062f\u064a\u0648 \u062d\u064a\u062b \u064a\u062a\u0645 \u0627\u0644\u0637\u0644\u0628 \u0645\u0646\u0643 \u0643\u0645\u0633\u062a\u062e\u062f\u0645 \u0625\u062f\u062e\u0627\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643. \u064a\u062a\u0645 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0645\u062b\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0647\u0630\u0647 \u0641\u0642\u0637 \u0644\u0644\u0647\u062f\u0641 \u0627\u0644\u062a\u064a \u064a\u062a\u0645 \u062c\u0645\u0639\u0647\u0627 \u0645\u0646 \u0623\u062c\u0644\u0647\u060c \u0648\u0623\u064a \u0623\u063a\u0631\u0627\u0636 \u0623\u062e\u0631\u0649 \u064a\u062a\u0645 \u062a\u062d\u062f\u064a\u062f\u0647\u0627 \u0641\u064a \u0646\u0642\u0637\u0629 \u0627\u0644\u062c\u0645\u0639 \u0648\u0630\u0644\u0643 \u0628\u0627\u0644\u062a\u0648\u0627\u0641\u0642 \u0645\u0639 \u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0647\u0630\u0647. \u0644\u0646 \u0646\u0642\u0648\u0645 \u0628\u0627\u0644\u0625\u0641\u0635\u0627\u062d \u0639\u0646 \u0623\u064a \u0645\u0646 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062a\u064a \u062a\u0648\u0641\u0631\u0647\u0627 \u0644\u0637\u0631\u0641 \u062b\u0627\u0644\u062b \u062f\u0648\u0646 \u0625\u0635\u062f\u0627\u0631\u0643 \u0627\u0644\u0645\u0648\u0627\u0641\u0642\u0629 \u0639\u0644\u0649 \u0630\u0644\u0643\u060c \u0628\u0627\u0633\u062a\u062b\u0646\u0627\u0621 \u0636\u0631\u0648\u0631\u0629 \u062a\u0648\u0641\u064a\u0631 \u062e\u062f\u0645\u0627\u062a \u0642\u0645\u062a \u0628\u062a\u062d\u062f\u064a\u062f \u0637\u0644\u0628\u0647\u0627.\n\n\u0625\u0644\u063a\u0627\u0621 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\n\u062a\u0633\u062a\u0637\u064a\u0639 \u0639\u0646\u062f\u0645\u0627 \u062a\u0631\u064a\u062f\u060c \u0627\u0644\u063a\u0627\u0621 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643 \u0641\u064a \u0627\u0644\u0645\u0648\u0642\u0639 \u0648\u062d\u0630\u0641 \u062c\u0645\u064a\u0639 \u0628\u064a\u0627\u0646\u0627\u062a\u0643 \u060c\u0648\u0630\u0644\u0643 \u0639\u0646 \u0637\u0631\u064a\u0642 \u0627\u0644\u0630\u0647\u0627\u0628 \u0644\u0635\u0641\u062d\u0629 \u0623\u062e\u0628\u0627\u0631\u064a \u0648\u0627\u062e\u062a\u064a\u0627\u0631 \u0635\u0641\u062d\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u062b\u0645 \u0627\u0644\u0636\u063a\u0637 \u0639\u0644\u064a \u062e\u064a\u0627\u0631 \u0627\u0644\u063a\u0627\u0621 \u0627\u0644\u062d\u0633\u0627\u0628\u060c \u0645\u0646 \u062b\u0645 \u0633\u0648\u0641 \u062a\u0638\u0647\u0631 \u0644\u0643 \u0631\u0633\u0627\u0644\u0629 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u063a\u0627\u0621 \u0627\u0644\u062d\u0633\u0627\u0628. \u062a\u0633\u062a\u0637\u064a\u0639 \u0639\u0646\u062f\u0645\u0627 \u062a\u0631\u064a\u062f \u0633\u062d\u0628 \u0645\u0648\u0627\u0641\u0642\u062a\u0643 \u0639\u0644\u0649 \u0627\u0633\u062a\u0644\u0627\u0645 \u0645\u062e\u0627\u0637\u0628\u0627\u062a \u062f\u0648\u0631\u064a\u0629 \u0628\u062e\u0635\u0648\u0635 \u0627\u0644\u0645\u0648\u0627\u0635\u0641\u0627\u062a\u060c \u0648\u0627\u0644\u0645\u0646\u062a\u062c\u0627\u062a\u060c \u0648\u0627\u0644\u062e\u062f\u0645\u0627\u062a\u060c \u0648\u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0627\u062a \u0648\u0630\u0644\u0643 \u0639\u0646 \u0637\u0631\u064a\u0642 \u0627\u0644\u0631\u062f \u0639\u0644\u0649 \u0648\u0635\u0644\u0629 "\u0625\u0644\u063a\u0627\u0621 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643" \u0641\u064a \u0627\u0644\u0645\u062e\u0627\u0637\u0628\u0627\u062a \u0627\u0644\u0642\u0627\u062f\u0645\u0629 \u0645\u0646\u0627. \u0627\u0644\u0631\u062c\u0627\u0621 \u0645\u0644\u0627\u062d\u0638\u0629 \u0623\u0646\u0646\u0627 \u0644\u0646 \u0646\u0642\u0648\u0645 \u0628\u0627\u0644\u0625\u0641\u0635\u0627\u062d \u0639\u0646 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0644\u0637\u0631\u0641 \u062b\u0627\u0644\u062b \u0644\u062a\u0645\u0643\u064a\u0646\u0647 \u0645\u0646 \u0625\u0631\u0633\u0627\u0644 \u0645\u062e\u0627\u0637\u0628\u0627\u062a \u062a\u0633\u0648\u064a\u0642 \u0645\u0628\u0627\u0634\u0631\u0629 \u0644\u0643 \u062f\u0648\u0646 \u0645\u0648\u0627\u0641\u0642\u062a\u0643 \u0627\u0644\u0645\u0633\u0628\u0642\u0629 \u0639\u0644\u0649 \u0627\u0644\u0642\u064a\u0627\u0645 \u0628\u0630\u0644\u0643.\n\n\u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629 (\u0643\u0648\u0643\u064a\u0632)\n\u064a\u062a\u0648\u062c\u0628 \u0639\u0644\u064a\u0643 \u0623\u0646 \u062a\u0639\u0644\u0645 \u0623\u0646\u0647 \u0645\u0646 \u0627\u0644\u0645\u0645\u0643\u0646 \u0623\u0646 \u064a\u062a\u0645 \u062c\u0645\u0639 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0648\u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u062a\u0644\u0642\u0627\u0626\u064a\u0627 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629 (\u0643\u0648\u0643\u064a\u0632). \u0648\u0647\u064a \u0645\u0644\u0641\u0627\u062a \u0646\u0635\u064a\u0629 \u0635\u063a\u064a\u0631\u0629 \u064a\u062a\u0645 \u0645\u0646 \u062e\u0644\u0627\u0644\u0647\u0627 \u062d\u0641\u0638 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0623\u0633\u0627\u0633\u064a\u0629 \u0627\u0644\u062a\u064a \u064a\u0633\u062a\u062e\u062f\u0645\u0647\u0627 \u0645\u0648\u0642\u0639 \u0627\u0644\u0634\u0628\u0643\u0629 \u0645\u0646 \u0623\u062c\u0644 \u062a\u062d\u062f\u064a\u062f \u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0627\u062a \u0627\u0644\u0645\u062a\u0643\u0631\u0631\u0629 \u0644\u0644\u0645\u0648\u0642\u0639 \u0648\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644\u060c \u0627\u0633\u062a\u0631\u062c\u0627\u0639 \u0627\u0633\u0645\u0643 \u0625\u0630\u0627 \u062a\u0645 \u0625\u062f\u062e\u0627\u0644\u0647 \u0645\u0633\u0628\u0642\u0627. \u0642\u062f \u0646\u0633\u062a\u062e\u062f\u0645 \u0647\u0630\u0647 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0645\u0646 \u0623\u062c\u0644 \u0645\u062a\u0627\u0628\u0639\u0629 \u0627\u0644\u0633\u0644\u0648\u0643 \u0648\u062a\u062c\u0645\u064a\u0639 \u0628\u064a\u0627\u0646\u0627\u062a \u0643\u0644\u064a\u0629 \u0645\u0646 \u0623\u062c\u0644 \u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u0645\u0648\u0642\u0639\u060c \u0648\u0627\u0633\u062a\u0647\u062f\u0627\u0641 \u0627\u0644\u0625\u0639\u0644\u0627\u0646\u0627\u062a \u0648\u062a\u0642\u064a\u064a\u0645 \u0627\u0644\u0641\u0639\u0627\u0644\u064a\u0629 \u0627\u0644\u0639\u0627\u0645\u0629 \u0644\u0645\u062b\u0644 \u0647\u0630\u0647 \u0627\u0644\u0625\u0639\u0644\u0627\u0646\u0627\u062a. \u0644\u0627 \u062a\u0646\u062f\u0645\u062c \u0647\u0630\u0647 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629 \u0636\u0645\u0646 \u0646\u0638\u0627\u0645 \u0627\u0644\u062a\u0634\u063a\u064a\u0644 \u0627\u0644\u062e\u0627\u0635 \u0628\u0643 \u0648\u0644\u0627 \u062a\u0624\u0630\u064a \u0645\u0644\u0641\u0627\u062a\u0643. \u0648\u0625\u0646 \u0643\u0646\u062a \u062a\u0641\u0636\u0644 \u0639\u062f\u0645 \u062c\u0645\u0639 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0645\u0646 \u062e\u0644\u0627\u0644 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629\u060c \u062a\u0633\u062a\u0637\u064a\u0639 \u0627\u062a\u0628\u0627\u0639 \u0625\u062c\u0631\u0627\u0621 \u0628\u0633\u064a\u0637 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0645\u0639\u0638\u0645 \u0627\u0644\u0645\u062a\u0635\u0641\u062d\u0627\u062a \u0648\u0627\u0644\u062a\u064a \u062a\u0645\u0643\u0646\u0651\u0643 \u0645\u0646 \u0631\u0641\u0636 \u062e\u0627\u0635\u064a\u0629 \u062a\u0646\u0632\u064a\u0644 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629. \u0648\u0644\u0643\u0646 \u0644\u0627 \u0628\u062f \u0623\u0646 \u062a\u0644\u0627\u062d\u0638\u060c \u0623\u0646 \u0627\u0644\u062e\u062f\u0645\u0627\u062a \u0627\u0644\u0645\u0648\u062c\u0647\u0651\u0629 \u0644\u0643 \u0634\u062e\u0635\u064a\u0627 \u0642\u062f \u062a\u062a\u0623\u062b\u0631 \u0641\u064a \u062d\u0627\u0644 \u0627\u062e\u062a\u064a\u0627\u0631 \u062a\u0639\u0637\u064a\u0644 \u062e\u064a\u0627\u0631 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629. \u0625\u0630\u0627 \u0631\u063a\u0628\u062a \u0641\u064a \u062a\u0639\u0637\u064a\u0644 \u062e\u0627\u0635\u064a\u0629 \u0625\u0646\u0632\u0627\u0644 \u0627\u0644\u0645\u0644\u0641\u0627\u062a \u0627\u0644\u0646\u0635\u064a\u0629 \u0627\u0636\u063a\u0637 \u0627\u0644\u0631\u0627\u0628\u0637 \u0647\u0646\u0627 \u0644\u0644\u062a\u0639\u0644\u064a\u0645\u0627\u062a \u0627\u0644\u062a\u064a \u0633\u062a\u0638\u0647\u0631 \u0641\u064a \u0646\u0627\u0641\u0630\u0629 \u0645\u0646\u0641\u0635\u0644\u0629.\n\n\u062d\u0645\u0627\u064a\u0629 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643\n\u0644\u0644\u0623\u0633\u0641 \u064a\u0639\u062a\u0628\u0631 \u0625\u0631\u0633\u0627\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0639\u0628\u0631 \u0627\u0644\u0625\u0646\u062a\u0631\u0646\u062a \u0623\u0645\u0631\u0627 \u0644\u0627 \u064a\u0645\u0643\u0646 \u0636\u0645\u0627\u0646\u0647 \u0639\u0644\u0649 \u0646\u062d\u0648 \u0643\u0644\u064a. \u0648\u0645\u0639 \u0627\u0644\u062a\u0632\u0627\u0645\u0646\u0627 \u0627\u0644\u062a\u0627\u0645 \u0628\u062d\u0645\u0627\u064a\u0629 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643\u060c \u0641\u0625\u0646\u0646\u0627 \u0644\u0627 \u0646\u0633\u062a\u0637\u064a\u0639 \u0636\u0645\u0627\u0646 \u0623\u0645\u0627\u0646 \u0625\u0631\u0633\u0627\u0644 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 \u0625\u0644\u0649 \u0627\u0644\u0645\u0648\u0642\u0639. \u0625\u0646 \u0623\u064a \u0628\u064a\u0627\u0646\u0627\u062a \u064a\u062a\u0645 \u0625\u0631\u0633\u0627\u0644\u0647\u0627\u060c \u0628\u0645\u0627 \u0641\u064a \u0630\u0644\u0643 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643\u060c \u062a\u0643\u0648\u0646 \u0639\u0644\u0649 \u0645\u0633\u0624\u0648\u0644\u064a\u062a\u0643 \u0623\u0646\u062a. \u0645\u0646 \u062c\u0627\u0646\u0628\u0646\u0627 \u0641\u0625\u0646\u0646\u0627 \u0646\u0639\u064a \u0645\u0639\u0627\u064a\u064a\u0631 \u0627\u0644\u0635\u0646\u0627\u0639\u0629 \u0648\u0646\u0633\u062a\u062e\u062f\u0645 \u062a\u0637\u0628\u064a\u0642\u0627\u062a \u0627\u0644\u0623\u0645\u0646 \u0645\u0646 \u0623\u062c\u0644 \u062d\u0645\u0627\u064a\u0629 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0645\u0646 \u0623\u064a \u0627\u062e\u062a\u0631\u0627\u0642 \u063a\u064a\u0631 \u0645\u0634\u0631\u0648\u0639 \u0623\u0648 \u0625\u0633\u0627\u0621\u0629 \u0627\u0633\u062a\u062e\u062f\u0627\u0645. \u0648\u0639\u0644\u064a\u0647 \u0648\u0644\u062f\u0649 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0646\u0627 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0641\u0625\u0646\u0646\u0627 \u0646\u0642\u0648\u0645 \u0628\u062a\u0637\u0628\u064a\u0642 \u0625\u062c\u0631\u0627\u0621\u0627\u062a \u0645\u0639\u0627\u064a\u064a\u0631 \u0627\u0644\u0635\u0646\u0627\u0639\u0629 \u0648\u0645\u0648\u0627\u0635\u0641\u0627\u062a \u0627\u0644\u0623\u0645\u0646 \u0645\u0646 \u0623\u062c\u0644 \u0645\u0646\u0639 \u0627\u0644\u0648\u0635\u0648\u0644 \u063a\u064a\u0631 \u0627\u0644\u0645\u0634\u0631\u0648\u0639 \u0625\u0644\u0649 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645.\n':'\u0645\u0631\u062d\u0628\u064b\u0627 \u0628\u0643 \u0641\u064a \u0645\u0646\u0635\u0629 "\u0627\u0644\u062a\u0642\u0646\u064a\u0646". \u064a\u0631\u062c\u0649 \u0642\u0631\u0627\u0621\u0629 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645 \u0627\u0644\u062a\u0627\u0644\u064a\u0629 \u0628\u0639\u0646\u0627\u064a\u0629 \u0642\u0628\u0644 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629. \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u0645\u0646\u0635\u062a\u0646\u0627\u060c \u0641\u0625\u0646\u0643 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645.\n\n1. \u0627\u0644\u0642\u0628\u0648\u0644 \u0628\u0627\u0644\u0634\u0631\u0648\u0637: \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u0645\u0646\u0635\u0629 "\u0627\u0644\u062a\u0642\u0646\u064a\u0646"\u060c \u0641\u0625\u0646\u0643 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645 \u0648\u0643\u0627\u0641\u0629 \u0627\u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0648\u0627\u0644\u0644\u0648\u0627\u0626\u062d \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647\u0627. \u0625\u0630\u0627 \u0643\u0646\u062a \u0644\u0627 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0623\u064a \u0645\u0646 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637\u060c \u064a\u0631\u062c\u0649 \u0639\u062f\u0645 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629.\n\n2. \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629: \u064a\u0645\u0643\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629 \u0644\u062a\u0635\u0641\u062d \u0627\u0644\u0645\u062d\u062a\u0648\u0649 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a \u0648\u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643 \u0641\u064a \u0627\u0644\u0643\u0648\u0631\u0633\u0627\u062a \u0648\u0627\u0644\u062f\u0648\u0631\u0627\u062a \u0627\u0644\u0645\u0642\u062f\u0645\u0629. \u064a\u062c\u0628 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629 \u0644\u0623\u063a\u0631\u0627\u0636 \u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0648\u0645\u0634\u0631\u0648\u0639\u0629 \u0641\u0642\u0637. \u064a\u064f\u0645\u0646\u0639 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629 \u0644\u0646\u0642\u0644 \u0623\u0648 \u0646\u0634\u0631 \u0623\u064a \u0645\u062d\u062a\u0648\u0649 \u063a\u064a\u0631 \u0642\u0627\u0646\u0648\u0646\u064a \u0623\u0648 \u0636\u0627\u0631 \u0623\u0648 \u0645\u0636\u0631 \u0623\u0648 \u0645\u0647\u064a\u0646 \u0623\u0648 \u0645\u0633\u064a\u0621 \u0623\u0648 \u0645\u0634\u0648\u0647.\n\n3. \u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0648\u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643: \u0644\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0628\u0639\u0636 \u0627\u0644\u0643\u0648\u0631\u0633\u0627\u062a \u0648\u0627\u0644\u062f\u0648\u0631\u0627\u062a\u060c \u0642\u062f \u064a\u064f\u0637\u0644\u0628 \u0645\u0646\u0643 \u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0648\u062a\u0642\u062f\u064a\u0645 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0645\u0639\u064a\u0646\u0629. \u064a\u062c\u0628 \u0623\u0646 \u062a\u0643\u0648\u0646 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0642\u062f\u0645\u0629 \u062f\u0642\u064a\u0642\u0629 \u0648\u0643\u0627\u0645\u0644\u0629 \u0648\u062d\u062f\u064a\u062b\u0629 \u0641\u064a \u062c\u0645\u064a\u0639 \u0627\u0644\u0623\u0648\u0642\u0627\u062a.\n\n4. \u0627\u0644\u0645\u062d\u062a\u0648\u0649: \u062c\u0645\u064a\u0639 \u0627\u0644\u0645\u062d\u062a\u0648\u064a\u0627\u062a \u0627\u0644\u0645\u0648\u062c\u0648\u062f\u0629 \u0639\u0644\u0649 \u0627\u0644\u0645\u0646\u0635\u0629 \u0647\u064a \u0645\u0644\u0643 \u0644\u0645\u0646\u0635\u0629 "\u0627\u0644\u062a\u0642\u0646\u064a\u0646" \u0623\u0648 \u0645\u0631\u062e\u0635\u0629 \u0644\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0645\u0646 \u0642\u0628\u0644\u0646\u0627. \u064a\u064f\u062d\u0638\u0631 \u0625\u0639\u0627\u062f\u0629 \u0625\u0646\u062a\u0627\u062c \u0623\u0648 \u062a\u0648\u0632\u064a\u0639 \u0623\u0648 \u062a\u0639\u062f\u064a\u0644 \u0623\u0648 \u0639\u0631\u0636 \u0623\u064a \u062c\u0632\u0621 \u0645\u0646 \u0627\u0644\u0645\u062d\u062a\u0648\u0649 \u062f\u0648\u0646 \u0625\u0630\u0646 \u0643\u062a\u0627\u0628\u064a \u0645\u0633\u0628\u0642 \u0645\u0646\u0627.\n\n5. \u0627\u0644\u062f\u0641\u0639: \u0642\u062f \u062a\u062a\u0637\u0644\u0628 \u0628\u0639\u0636 \u0627\u0644\u0643\u0648\u0631\u0633\u0627\u062a \u0648\u0627\u0644\u062f\u0648\u0631\u0627\u062a \u0631\u0633\u0648\u0645 \u0627\u0634\u062a\u0631\u0627\u0643. \u062c\u0645\u064a\u0639 \u0627\u0644\u0631\u0633\u0648\u0645 \u063a\u064a\u0631 \u0642\u0627\u0628\u0644\u0629 \u0644\u0644\u0627\u0633\u062a\u0631\u062f\u0627\u062f \u0645\u0627 \u0644\u0645 \u064a\u0646\u0635 \u0639\u0644\u0649 \u062e\u0644\u0627\u0641 \u0630\u0644\u0643. \u064a\u062c\u0628 \u0623\u0646 \u064a\u062a\u0645 \u0627\u0644\u062f\u0641\u0639 \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0648\u0633\u0627\u0626\u0644 \u0627\u0644\u062f\u0641\u0639 \u0627\u0644\u0645\u0642\u0628\u0648\u0644\u0629 \u0644\u062f\u064a\u0646\u0627.\n\n6. \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064a\u0629: \u0646\u062d\u0646 \u0646\u0628\u0630\u0644 \u0642\u0635\u0627\u0631\u0649 \u062c\u0647\u062f\u0646\u0627 \u0644\u0636\u0645\u0627\u0646 \u062f\u0642\u0629 \u0648\u0635\u062d\u0629 \u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0645\u0642\u062f\u0645\u0629 \u0639\u0644\u0649 \u0627\u0644\u0645\u0646\u0635\u0629\u060c \u0648\u0644\u0643\u0646\u0646\u0627 \u0644\u0627 \u0646\u0636\u0645\u0646 \u062e\u0644\u0648\u0647\u0627 \u0645\u0646 \u0627\u0644\u0623\u062e\u0637\u0627\u0621 \u0623\u0648 \u0639\u062f\u0645 \u0627\u0643\u062a\u0645\u0627\u0644\u0647\u0627. \u0644\u0627 \u0646\u062a\u062d\u0645\u0644 \u0623\u064a \u0645\u0633\u0624\u0648\u0644\u064a\u0629 \u0639\u0646 \u0627\u0644\u0623\u0636\u0631\u0627\u0631 \u0627\u0644\u0646\u0627\u062a\u062c\u0629 \u0639\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0623\u0648 \u0639\u062f\u0645 \u0627\u0644\u0642\u062f\u0631\u0629 \u0639\u0644\u0649 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0646\u0635\u0629 \u0623\u0648 \u0623\u064a \u0645\u062d\u062a\u0648\u0649 \u0645\u0648\u062c\u0648\u062f \u0639\u0644\u064a\u0647\u0627.\n\n7. \u0627\u0644\u062a\u0639\u062f\u064a\u0644\u0627\u062a: \u0646\u062d\u062a\u0641\u0638 \u0628\u0627\u0644\u062d\u0642 \u0641\u064a \u062a\u0639\u062f\u064a\u0644 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645 \u0641\u064a \u0623\u064a \u0648\u0642\u062a \u062f\u0648\u0646 \u0625\u0634\u0639\u0627\u0631 \u0645\u0633\u0628\u0642. \u064a\u064f\u0646\u0635\u062d \u0628\u0645\u0631\u0627\u062c\u0639\u0629 \u0647\u0630\u0647 \u0627\u0644\u0635\u0641\u062d\u0629 \u0628\u0627\u0646\u062a\u0638\u0627\u0645 \u0644\u0644\u062a\u0639\u0631\u0641 \u0639\u0644\u0649 \u0623\u064a \u062a\u063a\u064a\u064a\u0631\u0627\u062a.\n\n8. \u0631\u0648\u0627\u0628\u0637 \u0627\u0644\u0637\u0631\u0641 \u0627\u0644\u062b\u0627\u0644\u062b: \u0642\u062f \u062a\u062d\u062a\u0648\u064a \u0627\u0644\u0645\u0646\u0635\u0629 \u0639\u0644\u0649 \u0631\u0648\u0627\u0628\u0637 \u0644\u0645\u0648\u0627\u0642\u0639 \u0623\u062e\u0631\u0649 \u0644\u0627 \u0646\u0645\u0644\u0643\u0647\u0627 \u0623\u0648 \u0646\u062a\u062d\u0643\u0645 \u0641\u064a\u0647\u0627. \u0646\u062d\u0646 \u0644\u0633\u0646\u0627 \u0645\u0633\u0624\u0648\u0644\u064a\u0646 \u0639\u0646 \u0627\u0644\u0645\u062d\u062a\u0648\u0649 \u0623\u0648 \u0633\u064a\u0627\u0633\u0627\u062a \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629 \u0623\u0648 \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0627\u062a \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0623\u064a \u0645\u0648\u0627\u0642\u0639 \u062e\u0627\u0631\u062c\u064a\u0629.\n\n9. \u0625\u0646\u0647\u0627\u0621 \u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645: \u0646\u062d\u062a\u0641\u0638 \u0628\u0627\u0644\u062d\u0642 \u0641\u064a \u0625\u0646\u0647\u0627\u0621 \u0623\u0648 \u062a\u0639\u0644\u064a\u0642 \u0648\u0635\u0648\u0644\u0643 \u0625\u0644\u0649 \u0627\u0644\u0645\u0646\u0635\u0629 \u062f\u0648\u0646 \u0625\u0634\u0639\u0627\u0631 \u0645\u0633\u0628\u0642 \u0644\u0623\u064a \u0633\u0628\u0628 \u0645\u0646 \u0627\u0644\u0623\u0633\u0628\u0627\u0628 \u0628\u0645\u0627 \u0641\u064a \u0630\u0644\u0643 \u0627\u0646\u062a\u0647\u0627\u0643 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645.\n\n10. \u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u0627\u0644\u062d\u0627\u0643\u0645: \u062a\u062e\u0636\u0639 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645 \u0648\u062a\u0641\u0633\u0631 \u0648\u0641\u0642\u064b\u0627 \u0644\u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647\u0627 \u0641\u064a [\u0627\u0633\u0645 \u0627\u0644\u062f\u0648\u0644\u0629].\n\n\u0625\u0630\u0627 \u0643\u0627\u0646 \u0644\u062f\u064a\u0643 \u0623\u064a \u0623\u0633\u0626\u0644\u0629 \u0623\u0648 \u0627\u0633\u062a\u0641\u0633\u0627\u0631\u0627\u062a \u062d\u0648\u0644 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u0627\u0644\u0623\u062d\u0643\u0627\u0645\u060c \u064a\u0631\u062c\u0649 \u0627\u0644\u0627\u062a\u0635\u0627\u0644 \u0628\u0646\u0627 \u0639\u0644\u0649 [\u0627\u0644\u0628\u0631\u064a\u062f \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a \u0623\u0648 \u0631\u0642\u0645 \u0627\u0644\u0647\u0627\u062a\u0641].\n'
